div.p:
Each process has its own cwd in task_struct:
c
struct task_struct {
struct fs_struct *fs;  // Contains:
//   struct path pwd;  // Current cwd
//   struct path root; // Root directory
};

c
// Inside shell process
int builtin_cd(char **argv) {
if (chdir(argv[1]) != 0) {
perror("cd");
return 1;
}
return 0;
}
